settings.custom_liquid:
{% assign drop_product_1 = all_products['vietnamese-coffee-yogurt'] %}
{% assign drop_product_2 = all_products['strawberry-yogurt'] %}
{% assign drop_product_3 = all_products['classic-plain-yogurt'] %}

<section class="viora-drop-shop" id="viora-drop-shop">
  <div class="vds-shell">

    <aside class="vds-event-card">
      <div class="vds-event-image">
        {% if drop_product_1.featured_image %}
          <img src="{{ drop_product_1.featured_image | image_url: width: 600 }}" alt="{{ drop_product_1.title | escape }}">
        {% endif %}
      </div>

      <div class="vds-event-body">
        <p class="vds-back-label">← Back</p>
        <h2>Weekend Yogurt Drop</h2>
        <p>
          Pre-order handcrafted yogurt for weekend pickup. Choose your flavors, select pickup time, and checkout online.
        </p>

        <div class="vds-event-info">
          <button type="button" class="vds-info-button" data-vds-open-pickup>
            <span>📅</span>
            <div>
              <strong>Pickup this weekend</strong>
              <small>Choose date and time at checkout</small>
            </div>
            <b>›</b>
          </button>

          <button type="button" class="vds-info-button" data-vds-open-location>
            <span>📍</span>
            <div>
              <strong>Viora Creamery Pickup</strong>
              <small>Select pickup location below</small>
            </div>
            <b>›</b>
          </button>

          <button type="button" class="vds-info-button" data-vds-scroll-products>
            <span>🔥</span>
            <div>
              <strong>Drop is live</strong>
              <small>Inventory updates from Shopify stock</small>
            </div>
            <b>›</b>
          </button>
        </div>
      </div>
    </aside>

    <main class="vds-main">
      <div class="vds-top">
        <div>
          <p class="vds-eyebrow">Limited weekend drop</p>
          <h1>Pre-order fresh yogurt for pickup</h1>
          <p>Choose your items, reserve your pickup window, and pay online.</p>
        </div>

        <button type="button" class="vds-cart-button" data-vds-open-cart>
          Cart <span data-vds-cart-count>0</span>
        </button>
      </div>

      <div class="vds-tabs" data-vds-tabs>
        <button type="button" class="active" data-vds-tab="individual">Individual jars</button>
        <button type="button" data-vds-tab="pack">6-pack / flight</button>
      </div>

      <div class="vds-products is-showing-individual">

        {% if drop_product_1 != blank %}
          {% assign v1 = drop_product_1.selected_or_first_available_variant %}
          <article class="vds-product" data-vds-card-category="individual">
            <button
              type="button"
              class="vds-product-click"
              data-vds-category="individual"
              data-title="{{ drop_product_1.title | escape }}"
              data-description="{{ drop_product_1.description | strip_html | escape }}"
              data-price="{{ drop_product_1.price | money }}"
              data-variant-id="{{ v1.id }}"
              data-available="{{ drop_product_1.available }}"
              data-stock="{% if v1.inventory_management and v1.inventory_policy == 'deny' %}{{ v1.inventory_quantity }}{% else %}999{% endif %}"
              data-image="{% if drop_product_1.featured_image %}{{ drop_product_1.featured_image | image_url: width: 900 }}{% endif %}"
            >
              <div class="vds-product-image">
                {% if drop_product_1.featured_image %}
                  <img src="{{ drop_product_1.featured_image | image_url: width: 700 }}" alt="{{ drop_product_1.title | escape }}">
                {% endif %}
              </div>

              <div class="vds-product-body">
                <h3>{{ drop_product_1.title }}</h3>
                <p>{{ drop_product_1.price | money }}</p>

                {% if drop_product_1.available %}
                  {% if v1.inventory_management and v1.inventory_policy == 'deny' %}
                    <span class="vds-stock">{{ v1.inventory_quantity }} left</span>
                  {% else %}
                    <span class="vds-stock">Available</span>
                  {% endif %}
                {% else %}
                  <span class="vds-stock soldout">Sold out</span>
                {% endif %}

                <span class="vds-view-item">View Item / Add to Cart</span>
              </div>
            </button>
          </article>
        {% endif %}

        {% if drop_product_2 != blank %}
          {% assign v2 = drop_product_2.selected_or_first_available_variant %}
          <article class="vds-product" data-vds-card-category="individual">
            <button
              type="button"
              class="vds-product-click"
              data-vds-category="individual"
              data-title="{{ drop_product_2.title | escape }}"
              data-description="{{ drop_product_2.description | strip_html | escape }}"
              data-price="{{ drop_product_2.price | money }}"
              data-variant-id="{{ v2.id }}"
              data-available="{{ drop_product_2.available }}"
              data-stock="{% if v2.inventory_management and v2.inventory_policy == 'deny' %}{{ v2.inventory_quantity }}{% else %}999{% endif %}"
              data-image="{% if drop_product_2.featured_image %}{{ drop_product_2.featured_image | image_url: width: 900 }}{% endif %}"
            >
              <div class="vds-product-image">
                {% if drop_product_2.featured_image %}
                  <img src="{{ drop_product_2.featured_image | image_url: width: 700 }}" alt="{{ drop_product_2.title | escape }}">
                {% endif %}
              </div>

              <div class="vds-product-body">
                <h3>{{ drop_product_2.title }}</h3>
                <p>{{ drop_product_2.price | money }}</p>

                {% if drop_product_2.available %}
                  {% if v2.inventory_management and v2.inventory_policy == 'deny' %}
                    <span class="vds-stock">{{ v2.inventory_quantity }} left</span>
                  {% else %}
                    <span class="vds-stock">Available</span>
                  {% endif %}
                {% else %}
                  <span class="vds-stock soldout">Sold out</span>
                {% endif %}

                <span class="vds-view-item">View Item / Add to Cart</span>
              </div>
            </button>
          </article>
        {% endif %}

        {% if drop_product_3 != blank %}
          {% assign v3 = drop_product_3.selected_or_first_available_variant %}
          <article class="vds-product" data-vds-card-category="individual">
            <button
              type="button"
              class="vds-product-click"
              data-vds-category="individual"
              data-title="{{ drop_product_3.title | escape }}"
              data-description="{{ drop_product_3.description | strip_html | escape }}"
              data-price="{{ drop_product_3.price | money }}"
              data-variant-id="{{ v3.id }}"
              data-available="{{ drop_product_3.available }}"
              data-stock="{% if v3.inventory_management and v3.inventory_policy == 'deny' %}{{ v3.inventory_quantity }}{% else %}999{% endif %}"
              data-image="{% if drop_product_3.featured_image %}{{ drop_product_3.featured_image | image_url: width: 900 }}{% endif %}"
            >
              <div class="vds-product-image">
                {% if drop_product_3.featured_image %}
                  <img src="{{ drop_product_3.featured_image | image_url: width: 700 }}" alt="{{ drop_product_3.title | escape }}">
                {% endif %}
              </div>

              <div class="vds-product-body">
                <h3>{{ drop_product_3.title }}</h3>
                <p>{{ drop_product_3.price | money }}</p>

                {% if drop_product_3.available %}
                  {% if v3.inventory_management and v3.inventory_policy == 'deny' %}
                    <span class="vds-stock">{{ v3.inventory_quantity }} left</span>
                  {% else %}
                    <span class="vds-stock">Available</span>
                  {% endif %}
                {% else %}
                  <span class="vds-stock soldout">Sold out</span>
                {% endif %}

                <span class="vds-view-item">View Item / Add to Cart</span>
              </div>
            </button>
          </article>
        {% endif %}

      </div>
    </main>
  </div>

  <div class="vds-modal" data-vds-product-modal hidden>
    <div class="vds-modal-backdrop" data-vds-close-modal></div>

    <div class="vds-modal-card">
      <button type="button" class="vds-close" data-vds-close-modal>×</button>

      <div class="vds-modal-image">
        <img data-vds-modal-image src="" alt="">
      </div>

      <div class="vds-modal-content">
        <h2 data-vds-modal-title></h2>
        <p class="vds-modal-description" data-vds-modal-description></p>

        <div class="vds-qty-row">
          <button type="button" data-vds-qty-minus>−</button>
          <span data-vds-qty>1</span>
          <button type="button" data-vds-qty-plus>+</button>
        </div>

        <button type="button" class="vds-add-cart" data-vds-add-cart>
          Add to Cart <span data-vds-modal-price></span>
        </button>
      </div>
    </div>
  </div>

  <div class="vds-cart-drawer" data-vds-cart-drawer hidden>
    <div class="vds-cart-backdrop" data-vds-close-cart></div>

    <div class="vds-cart-panel">
      <button type="button" class="vds-close" data-vds-close-cart>×</button>

      <div class="vds-cart-head">
        <h2>Your Cart</h2>
        <span>Pickup</span>
      </div>

      <div data-vds-cart-items class="vds-cart-items"></div>

      <div class="vds-pickup-box">
        <h3>Location & Time</h3>

        <label>
          Pickup location
          <select id="vds-pickup-location">
            <option value="Viora Creamery Pickup">Viora Creamery Pickup</option>
            <option value="Farmers Market Pickup">Farmers Market Pickup</option>
            <option value="Pop-up Pickup">Pop-up Pickup</option>
          </select>
        </label>

        <label>
          Pickup date
          <select id="vds-pickup-date">
            <option value="Saturday">Saturday</option>
            <option value="Sunday">Sunday</option>
          </select>
        </label>

        <label>
          Pickup time
          <select id="vds-pickup-time">
            <option value="10:00 AM - 12:00 PM">10:00 AM - 12:00 PM</option>
            <option value="12:00 PM - 2:00 PM">12:00 PM - 2:00 PM</option>
            <option value="2:00 PM - 4:00 PM">2:00 PM - 4:00 PM</option>
          </select>
        </label>

        <label>
          Phone or email for pickup updates
          <input id="vds-customer-contact" type="text" placeholder="Phone or email">
        </label>

        <label class="vds-checkbox">
          <input id="vds-ready-notify" type="checkbox" checked>
          Notify me when my order is ready for pickup.
        </label>
      </div>

      <div class="vds-cart-summary">
        <div>
          <strong>Subtotal</strong>
          <strong data-vds-cart-subtotal>$0.00</strong>
        </div>

        <button type="button" class="vds-checkout-btn" data-vds-checkout>
          Choose Time & Checkout
        </button>
      </div>
    </div>
  </div>
</section>

<style>
  .viora-drop-shop {
    width: 100vw;
    margin-left: calc(50% - 50vw);
    background: #fbf8ee;
    color: #111;
    min-height: 100vh;
    font-family: inherit;
  }

  .vds-shell {
    display: grid;
    grid-template-columns: 320px 1fr;
    gap: 24px;
    max-width: 1480px;
    margin: 0 auto;
    padding: 34px 24px 70px;
  }

  .vds-event-card {
    background: #fff;
    border-radius: 16px;
    overflow: hidden;
    align-self: start;
    position: sticky;
    top: 20px;
    box-shadow: 0 18px 45px rgba(0,0,0,0.12);
  }

  .vds-event-image {
    height: 230px;
    background: linear-gradient(rgba(0,0,0,0.08), rgba(0,0,0,0.55)), #ddd;
  }

  .vds-event-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .vds-event-body {
    padding: 18px;
  }

  .vds-back-label {
    margin: 0 0 14px;
    color: #6b6575;
    font-size: 13px;
  }

  .vds-event-body h2 {
    margin: 0 0 12px;
    font-size: 25px;
    line-height: 1.1;
  }

  .vds-event-body p {
    color: #5f5a69;
    line-height: 1.5;
  }

  .vds-event-info {
    display: grid;
    gap: 12px;
    margin-top: 18px;
  }

  .vds-info-button {
    width: 100%;
    border: none;
    display: grid;
    grid-template-columns: auto 1fr auto;
    align-items: center;
    gap: 12px;
    padding: 12px;
    background: #f7f5f1;
    border-radius: 12px;
    text-align: left;
    cursor: pointer;
    color: #111;
    transition: transform 0.18s ease, background 0.18s ease, box-shadow 0.18s ease;
  }

  .vds-info-button:hover {
    background: #fff;
    transform: translateY(-1px);
    box-shadow: 0 8px 22px rgba(0,0,0,0.08);
  }

  .vds-info-button span {
    width: 34px;
    height: 34px;
    border-radius: 999px;
    display: grid;
    place-items: center;
    background: #fff;
  }

  .vds-info-button strong {
    display: block;
    font-size: 14px;
  }

  .vds-info-button small {
    display: block;
    color: #777;
    margin-top: 3px;
  }

  .vds-info-button b {
    font-size: 22px;
    line-height: 1;
    color: #777;
  }

  .vds-main {
    background: #fffefa;
    border-radius: 20px;
    padding: 26px;
    min-height: 760px;
  }

  .vds-top {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 20px;
    margin-bottom: 24px;
  }

  .vds-eyebrow {
    text-transform: uppercase;
    letter-spacing: 0.09em;
    color: #a65f33;
    font-weight: 900;
    font-size: 12px;
    margin: 0 0 8px;
  }

  .vds-top h1 {
    font-size: clamp(34px, 5vw, 64px);
    font-family: Georgia, 'Times New Roman', serif;
    line-height: 0.95;
    margin: 0 0 12px;
    max-width: 720px;
  }

  .vds-top p {
    margin: 0;
    color: #5f5a69;
    font-size: 16px;
  }

  .vds-cart-button {
    border: none;
    background: #211a1f;
    color: #fff;
    border-radius: 999px;
    padding: 12px 18px;
    font-weight: 900;
    cursor: pointer;
    white-space: nowrap;
  }

  .vds-cart-button span {
    background: #fff;
    color: #211a1f;
    border-radius: 999px;
    padding: 2px 8px;
    margin-left: 6px;
  }

  .vds-tabs {
    display: flex;
    gap: 8px;
    margin-bottom: 20px;
  }

  .vds-tabs button {
    border: none;
    background: #f0ecf4;
    border-radius: 999px;
    padding: 10px 15px;
    font-weight: 800;
    cursor: pointer;
  }

  .vds-tabs button.active {
    background: #fff;
    box-shadow: 0 4px 18px rgba(0,0,0,0.08);
  }

  .vds-products {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 18px;
  }

  .vds-products.is-showing-pack .vds-product[data-vds-card-category="individual"] {
    display: none;
  }

  .vds-products.is-showing-individual .vds-product[data-vds-card-category="pack"] {
    display: none;
  }

  .vds-empty-tab-message {
    background: #fff;
    border: 1px dashed #d9d2c5;
    border-radius: 14px;
    padding: 22px;
    color: #666;
    grid-column: 1 / -1;
  }

  .vds-product {
    background: #fff;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: 0 12px 28px rgba(0,0,0,0.08);
    border: 1px solid rgba(0,0,0,0.06);
  }

  .vds-product-click {
    width: 100%;
    border: none;
    background: transparent;
    padding: 0;
    text-align: left;
    cursor: pointer;
    color: #111;
  }

  .vds-product-image {
    height: 250px;
    background: #fbf4d6;
  }

  .vds-product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .vds-product-body {
    padding: 16px;
  }

  .vds-product-body h3 {
    font-size: 18px;
    margin: 0 0 8px;
  }

  .vds-product-body p {
    margin: 0 0 10px;
    font-weight: 800;
  }

  .vds-stock {
    display: inline-block;
    background: #ffe2d6;
    border-radius: 999px;
    padding: 6px 10px;
    font-size: 12px;
    font-weight: 900;
    margin-right: 8px;
  }

  .vds-stock.soldout {
    background: #e8e3de;
    color: #7f4a35;
  }

  .vds-view-item {
    display: inline-block;
    margin-top: 10px;
    background: #211a1f;
    color: #fff;
    border-radius: 999px;
    padding: 8px 12px;
    font-size: 12px;
    font-weight: 900;
  }

  .vds-modal,
  .vds-cart-drawer {
    position: fixed;
    inset: 0;
    z-index: 9999;
  }

  .vds-modal[hidden],
  .vds-cart-drawer[hidden] {
    display: none;
  }

  .vds-modal-backdrop,
  .vds-cart-backdrop {
    position: absolute;
    inset: 0;
    background: rgba(0,0,0,0.55);
  }

  .vds-modal-card {
    position: relative;
    background: #fff;
    max-width: 560px;
    max-height: 94vh;
    overflow: auto;
    margin: 3vh auto;
    border-radius: 18px;
    box-shadow: 0 22px 70px rgba(0,0,0,0.35);
  }

  .vds-close {
    position: absolute;
    top: 14px;
    right: 14px;
    width: 34px;
    height: 34px;
    border: none;
    border-radius: 999px;
    background: rgba(0,0,0,0.18);
    color: #fff;
    font-size: 22px;
    cursor: pointer;
    z-index: 3;
  }

  .vds-modal-image {
    height: 390px;
    background: #fbf4d6;
  }

  .vds-modal-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .vds-modal-content {
    padding: 22px;
  }

  .vds-modal-content h2 {
    margin: 0 0 12px;
    font-size: 24px;
  }

  .vds-modal-description {
    color: #5f5a69;
    line-height: 1.65;
    margin-bottom: 24px;
  }

  .vds-qty-row {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 16px;
    margin-bottom: 20px;
  }

  .vds-qty-row button {
    width: 36px;
    height: 32px;
    border: 1px solid #d8d3e5;
    background: #f7f4fb;
    border-radius: 6px;
    font-size: 20px;
    cursor: pointer;
  }

  .vds-add-cart,
  .vds-checkout-btn {
    width: 100%;
    border: none;
    background: #211a1f;
    color: #fff;
    border-radius: 12px;
    padding: 16px 18px;
    font-weight: 900;
    font-size: 16px;
    cursor: pointer;
  }

  .vds-add-cart {
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .vds-add-cart:disabled {
    background: #aaa;
    cursor: not-allowed;
  }

  .vds-cart-panel {
    position: absolute;
    right: 0;
    top: 0;
    width: min(560px, 96vw);
    height: 100%;
    background: #fff;
    padding: 24px;
    overflow-y: auto;
    box-shadow: -18px 0 60px rgba(0,0,0,0.28);
  }

  .vds-cart-panel .vds-close {
    background: #f2eef3;
    color: #111;
  }

  .vds-cart-head {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 22px;
  }

  .vds-cart-head h2 {
    margin: 0;
  }

  .vds-cart-head span {
    background: #d8f8ff;
    border: 1px solid #82ddeb;
    color: #08788b;
    border-radius: 7px;
    padding: 3px 8px;
    font-size: 12px;
    font-weight: 900;
  }

  .vds-cart-items {
    display: grid;
    gap: 14px;
    border-bottom: 1px solid #e7e3e8;
    padding-bottom: 20px;
    min-height: 80px;
  }

  .vds-cart-item {
    display: grid;
    grid-template-columns: 64px 1fr auto;
    gap: 12px;
    align-items: center;
  }

  .vds-cart-item img {
    width: 64px;
    height: 64px;
    object-fit: cover;
    border-radius: 8px;
    background: #fbf4d6;
  }

  .vds-cart-item h4 {
    margin: 0 0 4px;
    font-size: 15px;
  }

  .vds-cart-item p {
    margin: 0;
    font-weight: 800;
  }

  .vds-cart-qty {
    display: flex;
    align-items: center;
    border: 1px solid #dad5df;
    border-radius: 8px;
    overflow: hidden;
  }

  .vds-cart-qty button {
    border: none;
    background: #fff;
    width: 30px;
    height: 30px;
    cursor: pointer;
  }

  .vds-cart-qty span {
    min-width: 28px;
    text-align: center;
  }

  .vds-pickup-box {
    margin-top: 22px;
    padding: 18px;
    border: 2px solid #211a1f;
    border-radius: 12px;
  }

  .vds-pickup-box h3 {
    margin: 0 0 14px;
  }

  .vds-pickup-box label {
    display: grid;
    gap: 7px;
    font-weight: 900;
    font-size: 13px;
    margin-top: 14px;
  }

  .vds-pickup-box select,
  .vds-pickup-box input {
    width: 100%;
    border: 1px solid #d8d4dc;
    border-radius: 8px;
    padding: 12px;
    font-size: 14px;
  }

  .vds-checkbox {
    display: flex !important;
    grid-template-columns: auto 1fr;
    align-items: flex-start;
    gap: 10px !important;
    font-weight: 600 !important;
    line-height: 1.4;
  }

  .vds-checkbox input {
    width: auto !important;
    margin-top: 3px;
  }

  .vds-cart-summary {
    margin-top: 22px;
  }

  .vds-cart-summary > div {
    display: flex;
    justify-content: space-between;
    margin-bottom: 18px;
  }

  @media screen and (max-width: 980px) {
    .vds-shell {
      grid-template-columns: 1fr;
      padding: 18px;
    }

    .vds-event-card {
      position: static;
    }

    .vds-products {
      grid-template-columns: 1fr;
    }

    .vds-top {
      flex-direction: column;
    }

    .vds-product-image {
      height: 280px;
    }
  }
</style>

<script>
(function () {
  var selectedProduct = null;
  var selectedQty = 1;

  function moneyFromCents(cents) {
    return "$" + (cents / 100).toFixed(2);
  }

  function openProductModal(button) {
    var modal = document.querySelector("[data-vds-product-modal]");
    var img = document.querySelector("[data-vds-modal-image]");
    var title = document.querySelector("[data-vds-modal-title]");
    var desc = document.querySelector("[data-vds-modal-description]");
    var price = document.querySelector("[data-vds-modal-price]");
    var qty = document.querySelector("[data-vds-qty]");
    var addBtn = document.querySelector("[data-vds-add-cart]");

    selectedProduct = {
      variantId: button.dataset.variantId,
      title: button.dataset.title,
      description: button.dataset.description,
      price: button.dataset.price,
      image: button.dataset.image,
      available: button.dataset.available === "true",
      stock: Number(button.dataset.stock || 0)
    };

    selectedQty = 1;

    img.src = selectedProduct.image || "";
    img.alt = selectedProduct.title || "";
    title.textContent = selectedProduct.title || "";
    desc.textContent = selectedProduct.description || "Fresh handcrafted yogurt.";
    price.textContent = selectedProduct.price || "";
    qty.textContent = selectedQty;

    if (!selectedProduct.available || selectedProduct.stock <= 0) {
      addBtn.disabled = true;
      addBtn.textContent = "Sold Out";
    } else {
      addBtn.disabled = false;
      addBtn.innerHTML = 'Add to Cart <span data-vds-modal-price>' + selectedProduct.price + '</span>';
    }

    modal.hidden = false;
  }

  function closeProductModal() {
    var modal = document.querySelector("[data-vds-product-modal]");
    if (modal) modal.hidden = true;
  }

  function openCartDrawer() {
    var drawer = document.querySelector("[data-vds-cart-drawer]");
    if (drawer) drawer.hidden = false;
    refreshCart();
  }

  function closeCartDrawer() {
    var drawer = document.querySelector("[data-vds-cart-drawer]");
    if (drawer) drawer.hidden = true;
  }

  function refreshCart() {
    fetch("/cart.js")
      .then(function (res) { return res.json(); })
      .then(function (cart) {
        var countEls = document.querySelectorAll("[data-vds-cart-count]");
        var itemsEl = document.querySelector("[data-vds-cart-items]");
        var subtotalEl = document.querySelector("[data-vds-cart-subtotal]");

        countEls.forEach(function (el) {
          el.textContent = cart.item_count;
        });

        if (subtotalEl) subtotalEl.textContent = moneyFromCents(cart.items_subtotal_price);

        if (!itemsEl) return;

        if (!cart.items.length) {
          itemsEl.innerHTML = "<p>Your cart is empty.</p>";
          return;
        }

        itemsEl.innerHTML = cart.items.map(function (item) {
          var image = item.image || "";
          var title = (item.product_title || "").replace(/"/g, "&quot;");

          return (
            '<div class="vds-cart-item">' +
              '<img src="' + image + '" alt="' + title + '">' +
              '<div>' +
                '<h4>' + item.product_title + '</h4>' +
                '<p>' + moneyFromCents(item.final_line_price) + '</p>' +
              '</div>' +
              '<div class="vds-cart-qty">' +
                '<button type="button" data-vds-change-qty data-key="' + item.key + '" data-qty="' + (item.quantity - 1) + '">−</button>' +
                '<span>' + item.quantity + '</span>' +
                '<button type="button" data-vds-change-qty data-key="' + item.key + '" data-qty="' + (item.quantity + 1) + '">+</button>' +
              '</div>' +
            '</div>'
          );
        }).join("");
      });
  }

  function addToCart() {
    if (!selectedProduct || !selectedProduct.variantId) return;

    fetch("/cart/add.js", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "application/json"
      },
      body: JSON.stringify({
        items: [
          {
            id: Number(selectedProduct.variantId),
            quantity: selectedQty,
            properties: {
              "Order type": "Pickup preorder"
            }
          }
        ]
      })
    })
    .then(function (res) {
      if (!res.ok) throw new Error("Could not add item.");
      return res.json();
    })
    .then(function () {
      closeProductModal();
      openCartDrawer();
    })
    .catch(function () {
      alert("This item could not be added. Please check inventory or product setup.");
    });
  }

  function changeCartQty(key, quantity) {
    fetch("/cart/change.js", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "application/json"
      },
      body: JSON.stringify({
        id: key,
        quantity: Math.max(0, Number(quantity))
      })
    })
    .then(function (res) { return res.json(); })
    .then(refreshCart);
  }

  function checkoutWithPickup() {
    var location = document.getElementById("vds-pickup-location").value;
    var date = document.getElementById("vds-pickup-date").value;
    var time = document.getElementById("vds-pickup-time").value;
    var contact = document.getElementById("vds-customer-contact").value.trim();
    var notify = document.getElementById("vds-ready-notify").checked ? "Yes" : "No";

    if (!contact) {
      alert("Please enter your phone or email for pickup updates.");
      document.getElementById("vds-customer-contact").focus();
      return;
    }

    fetch("/cart/update.js", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "application/json"
      },
      body: JSON.stringify({
        attributes: {
          "Pickup location": location,
          "Pickup date": date,
          "Pickup time": time,
          "Pickup contact": contact,
          "Notify when ready": notify,
          "Order type": "Pickup preorder"
        }
      })
    })
    .then(function () {
      window.location.href = "/checkout";
    });
  }

  function initVioraInfoButtons() {
    var pickupBtn = document.querySelector("[data-vds-open-pickup]");
    var locationBtn = document.querySelector("[data-vds-open-location]");
    var liveBtn = document.querySelector("[data-vds-scroll-products]");
    var productGrid = document.querySelector(".vds-products");

    if (pickupBtn && pickupBtn.dataset.ready !== "true") {
      pickupBtn.dataset.ready = "true";
      pickupBtn.addEventListener("click", function () {
        openCartDrawer();

        setTimeout(function () {
          var pickupDate = document.getElementById("vds-pickup-date");
          if (pickupDate) {
            pickupDate.scrollIntoView({ behavior: "smooth", block: "center" });
            pickupDate.focus();
          }
        }, 250);
      });
    }

    if (locationBtn && locationBtn.dataset.ready !== "true") {
      locationBtn.dataset.ready = "true";
      locationBtn.addEventListener("click", function () {
        openCartDrawer();

        setTimeout(function () {
          var pickupLocation = document.getElementById("vds-pickup-location");
          if (pickupLocation) {
            pickupLocation.scrollIntoView({ behavior: "smooth", block: "center" });
            pickupLocation.focus();
          }
        }, 250);
      });
    }

    if (liveBtn && liveBtn.dataset.ready !== "true") {
      liveBtn.dataset.ready = "true";
      liveBtn.addEventListener("click", function () {
        if (productGrid) {
          productGrid.scrollIntoView({ behavior: "smooth", block: "start" });
        }
      });
    }
  }

  function initVioraTabs() {
    var tabWrap = document.querySelector("[data-vds-tabs]");
    var productGrid = document.querySelector(".vds-products");

    if (!tabWrap || !productGrid || tabWrap.dataset.ready === "true") return;

    tabWrap.dataset.ready = "true";

    tabWrap.querySelectorAll("[data-vds-tab]").forEach(function (tab) {
      tab.addEventListener("click", function () {
        var selected = tab.dataset.vdsTab;

        tabWrap.querySelectorAll("[data-vds-tab]").forEach(function (btn) {
          btn.classList.remove("active");
        });

        tab.classList.add("active");

        productGrid.classList.remove("is-showing-individual", "is-showing-pack");
        productGrid.classList.add(selected === "pack" ? "is-showing-pack" : "is-showing-individual");

        var visibleProducts = productGrid.querySelectorAll('[data-vds-card-category="' + selected + '"]');

        var oldMessage = productGrid.querySelector(".vds-empty-tab-message");
        if (oldMessage) oldMessage.remove();

        if (!visibleProducts.length) {
          var message = document.createElement("div");
          message.className = "vds-empty-tab-message";
          message.innerHTML = "<strong>No products in this section yet.</strong><br>Add a 6-pack or flight product in Shopify, then assign it to this tab in the code.";
          productGrid.appendChild(message);
        }
      });
    });

    productGrid.classList.add("is-showing-individual");
  }

  function initVioraDropShop() {
    initVioraInfoButtons();
    initVioraTabs();

    document.querySelectorAll(".vds-product-click").forEach(function (button) {
      if (button.dataset.ready === "true") return;
      button.dataset.ready = "true";
      button.addEventListener("click", function () {
        openProductModal(button);
      });
    });

    document.querySelectorAll("[data-vds-close-modal]").forEach(function (btn) {
      if (btn.dataset.ready === "true") return;
      btn.dataset.ready = "true";
      btn.addEventListener("click", closeProductModal);
    });

    document.querySelectorAll("[data-vds-close-cart]").forEach(function (btn) {
      if (btn.dataset.ready === "true") return;
      btn.dataset.ready = "true";
      btn.addEventListener("click", closeCartDrawer);
    });

    var plus = document.querySelector("[data-vds-qty-plus]");
    var minus = document.querySelector("[data-vds-qty-minus]");
    var qtyEl = document.querySelector("[data-vds-qty]");

    if (plus && plus.dataset.ready !== "true") {
      plus.dataset.ready = "true";
      plus.addEventListener("click", function () {
        var max = selectedProduct ? selectedProduct.stock : 99;
        selectedQty = Math.min(selectedQty + 1, max);
        qtyEl.textContent = selectedQty;
      });
    }

    if (minus && minus.dataset.ready !== "true") {
      minus.dataset.ready = "true";
      minus.addEventListener("click", function () {
        selectedQty = Math.max(1, selectedQty - 1);
        qtyEl.textContent = selectedQty;
      });
    }

    var addBtn = document.querySelector("[data-vds-add-cart]");
    if (addBtn && addBtn.dataset.ready !== "true") {
      addBtn.dataset.ready = "true";
      addBtn.addEventListener("click", addToCart);
    }

    document.querySelectorAll("[data-vds-open-cart]").forEach(function (btn) {
      if (btn.dataset.ready === "true") return;
      btn.dataset.ready = "true";
      btn.addEventListener("click", openCartDrawer);
    });

    document.addEventListener("click", function (event) {
      var qtyBtn = event.target.closest("[data-vds-change-qty]");
      if (qtyBtn) {
        changeCartQty(qtyBtn.dataset.key, qtyBtn.dataset.qty);
      }
    });

    var checkoutBtn = document.querySelector("[data-vds-checkout]");
    if (checkoutBtn && checkoutBtn.dataset.ready !== "true") {
      checkoutBtn.dataset.ready = "true";
      checkoutBtn.addEventListener("click", checkoutWithPickup);
    }

    refreshCart();
  }

  document.addEventListener("DOMContentLoaded", initVioraDropShop);
  document.addEventListener("shopify:section:load", initVioraDropShop);
  document.addEventListener("shopify:section:select", initVioraDropShop);
  setTimeout(initVioraDropShop, 800);
})();
</script>
